import java.nio.file.*; import java.util.regex.*; public class TestRegex { public static void main(String[] args) throws Exception { String sqlFile = new String(Files.readAllBytes(Paths.get("src/main/resources/static/db/metrics_evaluation_queries.sql"))); String targetFileName = "layer1a"; Pattern p = Pattern.compile("OUTPUT FILE\\\\s*:\\\\s*(" + targetFileName + "[^\\\\n]*\\\\.csv)[\\\\s\\\\S]*?(SELECT[\\\\s\\\\S]+?;)", Pattern.CASE_INSENSITIVE); Matcher m = p.matcher(sqlFile); if(m.find()) { System.out.println("MATCH: " + m.group(1)); } else { System.out.println("NO MATCH"); } } }
